import{_ as e,c as r,a as d,o}from"./app-CEcM0piI.js";const n={};function c(a,t){return o(),r("div",null,t[0]||(t[0]=[d('<p>默认情况下,所有容器都是以bridge方式连接到docker的一个虚拟网桥上的,docker会为容器分配网络地址,但如果启动顺序不同分配的地址也不同</p><h2 id="自定义网络" tabindex="-1"><a class="header-anchor" href="#自定义网络"><span>自定义网络</span></a></h2><p>自定义网络的地址组就可能和docker的不同了</p><p>加入自定义网络的容器才可以通过容器名互相访问，Docker的网络操作命令如下：</p><table><thead><tr><th>命令</th><th>说明</th><th>文档地址</th></tr></thead><tbody><tr><td>docker network create</td><td>创建一个网络</td><td>docker network create</td></tr><tr><td>docker network ls</td><td>查看所有网络</td><td>docker network ls</td></tr><tr><td>docker network rm</td><td>删除指定网络</td><td>docker network rm</td></tr><tr><td>docker network prune</td><td>清除未使用的网络</td><td>docker networkprune</td></tr><tr><td>docker network connect</td><td>使指定容器连接加入某网络</td><td>docker network connect</td></tr><tr><td>docker network disconnect</td><td>使指定容器连接离开某网络</td><td>docker network disconnect</td></tr><tr><td>docker network inspect</td><td>查看网络详细信息</td><td>docker network inspect</td></tr></tbody></table>',5)]))}const s=e(n,[["render",c]]),i=JSON.parse('{"path":"/tools/docker/4/","title":"4 网络","lang":"zh-CN","frontmatter":{"title":"4 网络","createTime":"2025/06/22 10:59:48","tags":["工具"],"permalink":"/tools/docker/4/"},"readingTime":{"minutes":0.77,"words":232},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/docker/4 网络.md","headers":[]}');export{s as comp,i as data};
